import json, pathlib

data = [
  {"id": "CAPEC-66", "name": "SQL Injection", "description": "An attacker exploits insufficient input validation to inject malicious SQL statements into queries processed by a back-end database. By inserting SQL syntax into user-controllable input fields such as search boxes, login forms, or URL parameters, the attacker can alter query logic to bypass authentication, extract sensitive data from tables, modify or delete records, and in some cases execute operating system commands via extended stored procedures like xp_cmdshell. Common techniques include UNION-based injection to combine result sets, error-based injection to extract data through verbose error messages, and time-based blind injection using WAITFOR DELAY or SLEEP() functions to infer data one bit at a time. Tools such as sqlmap automate the discovery and exploitation of these flaws across MySQL, PostgreSQL, MSSQL, and Oracle databases.", "severity": "High"},
  {"id": "CAPEC-7", "name": "Blind SQL Injection", "description": "The attacker exploits SQL injection vulnerabilities where the application does not return query results or error messages directly. Instead, the attacker infers information by observing differences in application behavior, such as response time differences (time-based blind) using functions like SLEEP() or BENCHMARK(), or by observing true/false conditions in page content (boolean-based blind). The attacker systematically extracts data character by character using binary search techniques with ASCII value comparisons, making the process slower but equally effective as classic SQL injection. Out-of-band techniques using DNS lookups or HTTP requests from the database server can accelerate extraction. Automated tools like sqlmap support blind injection with optimized inference algorithms.", "severity": "High"},
  {"id": "CAPEC-108", "name": "Command Line Injection", "description": "An attacker injects operating system commands through application inputs that are incorporated into command-line execution calls without proper sanitization. When applications use functions like system(), exec(), popen(), or backtick operators to execute shell commands with user-supplied data, the attacker can append additional commands using shell metacharacters such as semicolons, pipes, ampersands, backticks, or dollar-sign parentheses. This enables arbitrary command execution with the privileges of the application process, potentially allowing the attacker to read sensitive files, create reverse shells, install backdoors, pivot to internal systems, or exfiltrate data. The attack is particularly devastating when the application runs with elevated privileges such as root or SYSTEM.", "severity": "High"},
  {"id": "CAPEC-88", "name": "OS Command Injection", "description": "The attacker crafts input that is passed to operating system command interpreters (sh, bash, cmd.exe, PowerShell) for arbitrary command execution on the host system. This occurs when applications dynamically construct OS commands using insufficiently sanitized user input, typically through functions like os.system(), subprocess.call() with shell=True, Runtime.exec(), or PHP exec(). The attacker chains commands using operators like && (execute if previous succeeds), || (execute if previous fails), ; (sequential execution), or | (pipe output). Exploitation can lead to full system compromise, data exfiltration, lateral movement, and persistent backdoor installation. Defense requires parameterized command execution, input allowlisting, and avoiding shell interpreters entirely.", "severity": "High"},
  {"id": "CAPEC-86", "name": "XSS via HTTP Headers", "description": "The attacker injects malicious JavaScript or HTML through HTTP request headers such as User-Agent, Referer, X-Forwarded-For, or custom headers that the application logs, displays, or reflects in responses without proper encoding. When administrators view logs through web-based dashboards, or when applications reflect header values in error pages or debug output, the injected scripts execute in the context of the viewer's browser session. This can lead to session hijacking of administrator accounts, privilege escalation, internal network reconnaissance via the admin's browser, and persistent XSS if the headers are stored in databases or log files that are later rendered in web interfaces.", "severity": "Medium"},
  {"id": "CAPEC-63", "name": "Cross-Site Scripting (XSS)", "description": "The attacker injects malicious client-side scripts into web pages viewed by other users by exploiting insufficient input validation and output encoding. There are three primary variants: Stored XSS where the payload is persisted in the application database and served to every visitor, Reflected XSS where the payload is embedded in a URL or form submission and reflected back in the immediate response, and DOM-based XSS where client-side JavaScript processes untrusted data into dangerous sinks like innerHTML or eval(). Successful exploitation allows the attacker to steal session cookies and authentication tokens, perform actions on behalf of the victim, redirect users to phishing pages, deploy keyloggers, deface web pages, and propagate XSS worms. Modern exploitation techniques bypass WAFs using encoding tricks, event handlers, and mutation XSS.", "severity": "High"},
  {"id": "CAPEC-85", "name": "AJAX Fingerprinting", "description": "The attacker sends specially crafted asynchronous HTTP requests (AJAX calls) to enumerate the server-side framework, libraries, API endpoints, and application architecture. By analyzing response headers, error messages, response formats, timing characteristics, and default endpoint patterns, the attacker can identify technologies like jQuery, Angular, React, Django REST Framework, or ASP.NET Web API. This reconnaissance technique helps the attacker map the application's attack surface, identify known vulnerabilities in detected frameworks, understand API patterns for further exploitation, and plan targeted attacks based on technology-specific weaknesses.", "severity": "Low"},
  {"id": "CAPEC-209", "name": "XSS Using MIME Type Mismatch", "description": "The attacker uploads or serves a file with a content type that differs from its actual content, exploiting browsers that perform MIME sniffing to determine how to handle the response. For example, a file served as text/plain but containing HTML and JavaScript may be rendered as HTML by browsers that ignore the declared Content-Type header. This technique bypasses security controls that filter based on file extensions or declared MIME types. The attack is particularly effective against file upload functionality, content delivery networks, and applications that serve user-uploaded content. Proper mitigation requires setting X-Content-Type-Options: nosniff headers and validating file content matches its declared type.", "severity": "Medium"},
  {"id": "CAPEC-198", "name": "XSS Targeting Error Pages", "description": "The attacker injects malicious scripts through parameters that are reflected in application error pages, such as 404 Not Found pages, 500 Internal Server Error pages, or custom error handlers. Many applications include the requested URL, query parameters, or user input in error responses without proper HTML encoding, creating reflected XSS opportunities. Custom error pages that display the invalid input back to the user, debug mode error pages that show request details, and framework default error handlers are common targets. The attack is often overlooked during security testing because error pages receive less scrutiny than primary application functionality.", "severity": "Medium"},
  {"id": "CAPEC-242", "name": "Code Injection", "description": "The attacker introduces executable code through user input channels that is subsequently interpreted and executed by the application runtime. This encompasses a broad category of attacks including server-side template injection (SSTI) where template expressions like {{7*7}} or ${7*7} are evaluated, eval() injection in languages like Python, JavaScript, and PHP, expression language injection in Java (SpEL, OGNL, EL), and CRLF injection that manipulates HTTP headers. The injected code executes with the full privileges of the application process, potentially enabling remote code execution, file system access, network pivoting, and complete server compromise. Unlike command injection, code injection targets the application's own interpreter rather than the OS shell.", "severity": "High"},
  {"id": "CAPEC-19", "name": "Embedding Scripts within Scripts", "description": "The attacker nests script content within other script contexts to evade input validation and output encoding defenses. Techniques include double-encoding payloads (encoding special characters multiple times so they survive decoding layers), nesting script tags within event handlers, using JavaScript protocol handlers in href/src attributes, exploiting parser differentials between HTML and JavaScript contexts, and leveraging browser-specific parsing quirks. For example, an attacker might encode a script tag within a CSS expression, embed JavaScript within SVG elements, or use HTML entities within JavaScript string contexts. This technique is commonly used to bypass Web Application Firewalls (WAFs) and content security policies.", "severity": "High"},
  {"id": "CAPEC-244", "name": "XSS via HTTP Query Strings", "description": "The attacker crafts URLs containing malicious JavaScript payloads in query string parameters that are reflected in the application's response without proper encoding. When a victim clicks the crafted link (delivered via phishing email, social media, or a compromised website), the script executes in their browser within the application's origin. The attacker can steal session tokens, capture keystrokes, modify page content, redirect to phishing pages, or perform actions on behalf of the victim. Modern attacks use URL shorteners to disguise malicious URLs and leverage open redirects to chain with the XSS for more convincing social engineering.", "severity": "Medium"},
  {"id": "CAPEC-250", "name": "XML Injection", "description": "The attacker crafts malicious XML input to manipulate XML document processing, alter application logic, or extract sensitive information. This includes injecting additional XML elements to modify document structure, manipulating XPath queries to bypass authentication or extract data, exploiting XML Schema validation weaknesses, and leveraging XML-specific features like CDATA sections and processing instructions. When applications construct XML documents using string concatenation with user input, the attacker can inject new elements, modify existing values, or alter the document's semantic meaning. This can lead to authentication bypass, authorization circumvention, data tampering, and information disclosure.", "severity": "High"},
  {"id": "CAPEC-112", "name": "Brute Force", "description": "The attacker systematically enumerates all possible values for a secret (password, encryption key, PIN, session token) to determine the correct value through exhaustive trial. This category encompasses password guessing against login forms, cryptographic key brute-forcing, PIN cracking, directory and file brute-forcing to discover hidden content, and parameter fuzzing to discover hidden API endpoints. The feasibility depends on the secret's entropy, rate limiting controls, account lockout policies, and computational resources available. Distributed attacks across botnets, GPU-accelerated cracking with hashcat, and cloud computing resources have dramatically reduced the time required. Tools include Hydra, Medusa, Burp Intruder, and custom scripts.", "severity": "Medium"},
  {"id": "CAPEC-49", "name": "Password Brute Forcing", "description": "The attacker exhaustively tries password combinations against user accounts to gain unauthorized access. Online attacks target login forms, APIs, SSH, RDP, and other authentication endpoints directly, while offline attacks target captured password hashes using tools like hashcat and John the Ripper with GPU acceleration. Attack strategies include dictionary attacks using wordlists like rockyou.txt, rule-based mutations (appending numbers, leetspeak substitutions, capitalization variations), hybrid attacks combining dictionaries with brute force, and mask attacks targeting known password patterns. The attack effectiveness depends on password complexity requirements, account lockout thresholds, rate limiting, CAPTCHA implementation, and whether multi-factor authentication is enforced.", "severity": "Medium"},
  {"id": "CAPEC-55", "name": "Rainbow Table Password Cracking", "description": "The attacker uses precomputed lookup tables (rainbow tables) that map hash values back to their plaintext inputs to rapidly reverse password hashes without performing real-time computation. Rainbow tables trade storage space for computation time, with tables for common algorithms like MD5, SHA-1, and NTLM available in sizes ranging from gigabytes to terabytes covering character sets of varying complexity. The attack is effective against unsalted hashes where the same password always produces the same hash value. Modern defenses include using salted hashes (where a unique random value is prepended to each password before hashing) and adaptive hashing algorithms like bcrypt, scrypt, or Argon2 that are computationally expensive to crack.", "severity": "Medium"},
  {"id": "CAPEC-565", "name": "Password Spraying", "description": "The attacker tries a small number of commonly used passwords (such as 'Password1!', 'Summer2024!', 'Welcome1') against a large number of accounts simultaneously to avoid triggering account lockout thresholds that typically activate after 3-5 failed attempts per account. By rotating through many accounts with each password attempt and introducing delays between rounds, the attacker stays below detection thresholds. This technique is particularly effective against organizations with weak password policies, especially those requiring only basic complexity (uppercase, lowercase, number, special character) which leads to predictable patterns. Common targets include Active Directory environments, Office 365 tenants, VPN gateways, and cloud authentication endpoints. Tools include Spray, Ruler, and MSOLSpray.", "severity": "Medium"},
  {"id": "CAPEC-600", "name": "Credential Stuffing", "description": "The attacker automates login attempts using large databases of username-password pairs stolen from previous data breaches, exploiting the widespread practice of password reuse across multiple services. Breach databases containing billions of credentials are available on dark web marketplaces and through data aggregation services. The attacker uses automated tools like Sentry MBA, OpenBullet, or custom scripts with proxy rotation and CAPTCHA-solving services to test credentials at scale against target applications. Account takeover rates of 0.1-2% are typical, meaning even small breach databases can yield thousands of compromised accounts. The attack is particularly effective against consumer-facing applications and services that lack multi-factor authentication.", "severity": "High"},
  {"id": "CAPEC-50", "name": "Password Recovery Exploitation", "description": "The attacker abuses password recovery and account reset mechanisms to gain unauthorized access to user accounts. Attack vectors include exploiting weak security questions (answers discoverable through social media or public records), intercepting password reset emails through email account compromise or MitM attacks, manipulating password reset tokens that use predictable patterns or insufficient entropy, exploiting race conditions in reset workflows, and abusing account recovery flows that use SMS-based verification vulnerable to SIM swapping. Some applications expose user enumeration through different responses for valid versus invalid accounts during the reset process, enabling targeted attacks against confirmed accounts.", "severity": "Medium"},
  {"id": "CAPEC-560", "name": "Use of Known Domain Credentials", "description": "The attacker uses credentials obtained from one domain or service to access accounts on other systems, exploiting password reuse and shared authentication infrastructure. In enterprise environments, Active Directory credentials granted access to one system may work across email, VPN, file shares, intranet applications, and cloud services. The attacker may obtain initial credentials through phishing, credential dumping (Mimikatz, secretsdump), keylogging, or purchasing breach data, then systematically test those credentials across all accessible services. This lateral movement technique is particularly effective in environments without network segmentation or where single sign-on extends trust across many applications.", "severity": "High"},
  {"id": "CAPEC-16", "name": "Dictionary-based Password Attack", "description": "The attacker uses precompiled wordlists containing common passwords, dictionary words, and known leaked passwords to systematically guess account credentials. Wordlists range from basic dictionaries (rockyou.txt with 14 million entries) to targeted lists incorporating organization-specific terms, city names, sports teams, and seasonal patterns. Sophisticated attacks apply transformation rules including leetspeak substitution (a->@, e->3, s->$), case variations, appending numbers and years, prepending special characters, and combining words. Language-specific and culture-specific wordlists improve success rates against international targets. The attack is effective against passwords based on dictionary words even when basic complexity is enforced.", "severity": "Medium"},
  {"id": "CAPEC-70", "name": "Try Common Usernames and Passwords", "description": "The attacker attempts authentication using well-known default username and password combinations commonly shipped with hardware, software, and cloud services. Default credentials for network devices (admin/admin, admin/password), database systems (sa/empty, root/empty, postgres/postgres), web applications (admin/admin, administrator/changeme), IoT devices (admin/1234, root/root), and cloud platforms are extensively documented in resources like default-password.info and SecLists. Many organizations fail to change default credentials during deployment, especially on internal systems, development environments, network infrastructure, and IoT devices. Automated scanners like Nmap scripts, Metasploit modules, and specialized tools like Changeme systematically test known defaults across discovered services.", "severity": "Medium"},
  {"id": "CAPEC-94", "name": "Man in the Middle Attack", "description": "The attacker positions themselves between two communicating parties to intercept, inspect, and potentially modify traffic in real time without either party's knowledge. Techniques include ARP spoofing on local networks (using tools like Bettercap or Ettercap), DNS spoofing to redirect traffic, BGP hijacking for internet-scale interception, rogue Wi-Fi access points (Evil Twin attacks), SSL/TLS stripping to downgrade HTTPS connections to HTTP, and compromised certificate authorities issuing fraudulent certificates. The attacker can capture credentials, session tokens, and sensitive data in transit, inject malicious content into web pages, modify API responses, and perform real-time transaction manipulation. In enterprise environments, this enables credential harvesting, email interception, and supply chain attacks.", "severity": "High"},
  {"id": "CAPEC-157", "name": "Sniffing Attacks", "description": "The attacker captures network traffic passively using packet analyzers to extract sensitive data transmitted in cleartext or weakly encrypted protocols. Using tools like Wireshark, tcpdump, or NetworkMiner on compromised network segments, the attacker can harvest credentials from protocols like HTTP, FTP, Telnet, SMTP, POP3, and LDAP. In switched networks, the attacker may first perform ARP spoofing, MAC flooding, or VLAN hopping to redirect traffic through their monitoring point. Wireless sniffing using monitor mode on Wi-Fi adapters captures all traffic on the wireless channel. The attack is particularly effective in environments with insufficient network segmentation, unencrypted internal communications, or legacy protocols that lack TLS support.", "severity": "High"},
  {"id": "CAPEC-272", "name": "Protocol Manipulation", "description": "The attacker exploits weaknesses in network protocol implementations, specification ambiguities, or design flaws to subvert security controls, bypass authentication, or cause unexpected behavior. This includes exploiting protocol downgrade attacks (forcing TLS 1.0 instead of 1.3), manipulating protocol state machines, abusing protocol extension mechanisms, exploiting differences in how multiple implementations handle edge cases (request smuggling), and leveraging protocol-level race conditions. Specific examples include HTTP desynchronization attacks, TCP session hijacking, DNS cache poisoning, SMTP relay abuse, and protocol confusion attacks where one protocol's traffic is interpreted as another's. These attacks often bypass application-layer defenses because they operate at the protocol level.", "severity": "High"},
  {"id": "CAPEC-220", "name": "XSS via Client-Side Parameters", "description": "The attacker injects malicious scripts through client-side parameters such as URL fragment identifiers (after the # symbol), DOM properties, or client-side storage that are processed by JavaScript without server-side involvement. Since fragment identifiers are never sent to the server, server-side security controls and WAFs cannot detect or block these attacks. The malicious payload is processed entirely by client-side JavaScript that reads from sources like document.location.hash, window.name, document.referrer, or localStorage and writes to dangerous sinks like innerHTML, document.write(), or eval(). This DOM-based XSS variant is increasingly common in single-page applications (SPAs) built with frameworks like React, Angular, and Vue that perform extensive client-side rendering.", "severity": "Medium"},
  {"id": "CAPEC-101", "name": "Server Side Include (SSI) Injection", "description": "The attacker injects Server-Side Include directives into web pages that are processed by the web server before being sent to the client. SSI directives like <!--#exec cmd='command'--> allow execution of arbitrary operating system commands, while <!--#include virtual='/etc/passwd'--> can read system files. When user input is reflected in pages processed with SSI (typically .shtml or .shtm files), the attacker can achieve remote code execution, read sensitive configuration files, and enumerate the server environment. The attack targets legacy web servers with SSI enabled (Apache with mod_include, IIS) and is often overlooked in modern security assessments despite remaining viable on many enterprise systems.", "severity": "High"},
  {"id": "CAPEC-253", "name": "Remote Code Inclusion", "description": "The attacker forces the application to include and execute code from a remote server by manipulating file inclusion parameters. In PHP applications, functions like include(), require(), and file_get_contents() with allow_url_include enabled can fetch and execute PHP code from attacker-controlled URLs. The attacker hosts a malicious PHP file on their server and passes its URL as a parameter value, causing the target server to download and execute it with the web application's privileges. This Remote File Inclusion (RFI) vulnerability enables immediate remote code execution, webshell deployment, and full server compromise. Local File Inclusion (LFI) variants leverage log poisoning, /proc/self/environ, or PHP filter wrappers to achieve code execution using local files.", "severity": "High"},
  {"id": "CAPEC-126", "name": "Path Traversal", "description": "The attacker manipulates file path references using sequences like ../ (dot-dot-slash), ..\\, URL-encoded variants (%2e%2e%2f), double-encoding, or Unicode/UTF-8 encoding to escape the intended directory and access files elsewhere on the file system. Common targets include /etc/passwd, /etc/shadow, web application configuration files, database connection strings, source code, SSH keys, and cloud instance metadata. The attack exploits insufficient validation of file path parameters in download functions, file viewers, template engines, and log viewers. Advanced techniques include null byte injection (%00) to truncate file extensions, path normalization bypasses, and leveraging symlinks. Successful exploitation can lead to source code disclosure, credential theft, and in combination with other vulnerabilities, remote code execution.", "severity": "High"},
  {"id": "CAPEC-76", "name": "Manipulating Web Input to File System Calls", "description": "The attacker crafts web application input to trigger unintended file system operations on the server. This encompasses path traversal to read arbitrary files, file upload manipulation to write to unintended locations, file deletion through parameter tampering, and symbolic link attacks that redirect file operations to sensitive targets. When web applications pass user-controlled input to file system functions (open, read, write, delete, rename) without proper validation and sandboxing, the attacker can read configuration files, overwrite application code, plant webshells in web-accessible directories, or delete critical system files. The attack is amplified when the application runs with elevated privileges, enabling access to system-level files and directories.", "severity": "High"},
  {"id": "CAPEC-100", "name": "Overflow Buffers", "description": "The attacker provides input exceeding the boundaries of a fixed-size memory buffer, causing adjacent memory to be overwritten with attacker-controlled data. Stack-based buffer overflows can overwrite the return address to redirect execution to injected shellcode or ROP gadget chains. Heap-based overflows corrupt heap metadata or adjacent heap objects to achieve arbitrary write primitives. The attack is prevalent in C/C++ applications that use unsafe functions like strcpy(), gets(), sprintf(), and memcpy() without bounds checking. Modern exploits bypass protections like ASLR (through information leaks), stack canaries (through format string vulnerabilities or overwriting other variables), and DEP/NX (through return-oriented programming). Buffer overflows remain one of the most dangerous vulnerability classes, enabling remote code execution.", "severity": "High"},
  {"id": "CAPEC-123", "name": "Buffer Manipulation", "description": "The attacker manipulates buffer contents through crafted input to alter program execution flow, corrupt data structures, or leak sensitive information from adjacent memory regions. This encompasses techniques beyond simple overflow, including off-by-one errors that corrupt a single byte (often a null terminator or frame pointer), heap spraying to place controlled data at predictable addresses, integer overflows that lead to undersized buffer allocations, and use-after-free conditions where freed buffer contents are manipulated before reuse. Modern exploitation chains multiple primitives: an information leak reveals memory layout (defeating ASLR), then a write primitive overwrites a code pointer, and finally a ROP chain achieves arbitrary code execution while bypassing DEP.", "severity": "High"},
  {"id": "CAPEC-10", "name": "Buffer Overflow via Environment Variables", "description": "The attacker sets excessively long or specially crafted values in environment variables that are read by a vulnerable application without proper bounds checking. Programs that use getenv() and copy the result into fixed-size buffers, or that process environment variables like PATH, HOME, LD_LIBRARY_PATH, or application-specific variables without length validation, are susceptible. In SUID/SGID programs on Unix systems, this can lead to local privilege escalation to root. The technique is also used against CGI programs that receive user input through environment variables (QUERY_STRING, HTTP_USER_AGENT, etc.), potentially enabling remote code execution on web servers running vulnerable CGI applications.", "severity": "High"},
  {"id": "CAPEC-14", "name": "Client-side Injection: Buffer Overflow", "description": "The attacker triggers a buffer overflow vulnerability in client-side software such as web browsers, PDF readers, media players, office applications, or email clients by providing specially crafted content that exceeds buffer boundaries during parsing or rendering. The malicious content may be delivered through compromised websites (drive-by download), email attachments, embedded documents, or file downloads. Successful exploitation allows the attacker to execute arbitrary code on the victim's workstation with the privileges of the user, potentially leading to malware installation, credential theft, and lateral movement into the corporate network. This is a primary initial access technique used in targeted attacks and APT campaigns.", "severity": "High"},
  {"id": "CAPEC-24", "name": "Filter Failure through Buffer Overflow", "description": "The attacker exploits a buffer overflow condition in an input validation or filtering component to bypass security checks that would otherwise block malicious input. By overflowing the filter's internal buffer, the attacker can corrupt the filter's state, cause it to crash (failing open rather than closed), or inject data past the filter boundary that is then processed by downstream components without validation. This meta-attack technique combines a buffer overflow with whatever subsequent attack the filter was designed to prevent, such as SQL injection, XSS, command injection, or path traversal. The technique highlights the importance of defense in depth since the failure of a single security layer exposes the application.", "severity": "High"},
  {"id": "CAPEC-256", "name": "SOAP Array Overflow", "description": "The attacker sends SOAP XML messages containing arrays with declared sizes that exceed the actual number of elements, or conversely arrays with more elements than declared, to trigger buffer overflows or memory corruption in SOAP processing libraries. XML-based web services that deserialize SOAP messages into fixed-size memory structures are vulnerable when they trust the declared array dimensions without validation. The attack can cause denial of service through memory exhaustion (XML bombs), heap corruption leading to code execution, or information disclosure through out-of-bounds reads. This affects enterprise SOAP services built with frameworks that parse XML arrays into native data structures without proper bounds checking.", "severity": "High"},
  {"id": "CAPEC-153", "name": "Input Data Manipulation", "description": "The attacker manipulates application input parameters, form fields, cookies, headers, or API request bodies to cause unexpected behavior, bypass security controls, or alter application logic. Techniques include parameter tampering (modifying hidden form fields, prices, or quantities), HTTP parameter pollution (submitting duplicate parameters to exploit parsing differences), type juggling (submitting unexpected data types), mass assignment (adding object properties not exposed in the UI), and encoding manipulation (using alternate character encodings to bypass filters). This broad attack category underlies many specific vulnerability classes and is the foundation of most web application attacks. Effective defense requires server-side validation of all inputs against strict allowlists.", "severity": "Medium"},
  {"id": "CAPEC-125", "name": "Flooding", "description": "The attacker sends an overwhelming volume of requests, packets, or data to exhaust system resources and deny service to legitimate users. Network-layer floods include SYN floods (exploiting the TCP three-way handshake), UDP floods, ICMP floods, and amplification attacks using DNS, NTP, or memcached reflectors that multiply traffic volume by 10-50x. Application-layer floods target specific endpoints with expensive operations like login processing, search queries, file uploads, or API calls. Distributed attacks launched from botnets comprising hundreds of thousands of compromised devices can generate traffic volumes exceeding 1 Tbps. Defense requires multi-layered mitigation including network-level filtering, CDN protection, rate limiting, and application-level circuit breakers.", "severity": "Medium"},
  {"id": "CAPEC-130", "name": "Excessive Allocation", "description": "The attacker crafts requests that cause the application to allocate disproportionately large amounts of server resources (memory, CPU, disk space, database connections, thread pools) relative to the cost of the request. Examples include uploading extremely large files, requesting generation of massive reports, triggering expensive database queries through crafted search parameters, creating deeply nested data structures that consume exponential memory during parsing, and exploiting XML entity expansion (Billion Laughs attack) to consume gigabytes of memory from a few kilobytes of input. A single attacker can often exhaust server resources without a botnet by targeting asymmetric resource consumption patterns where a small request triggers massive server-side computation.", "severity": "Medium"},
  {"id": "CAPEC-131", "name": "Resource Leak Exposure", "description": "The attacker triggers conditions in the application that cause resources (memory, file handles, database connections, thread pool threads, network sockets) to be allocated but never properly released. By repeatedly triggering these resource leaks, the attacker gradually exhausts the application's resource pool, leading to degraded performance and eventually complete denial of service. Techniques include initiating connections and abandoning them (leaving half-open connections), triggering error conditions that skip resource cleanup code, exploiting exception handling paths that don't properly release resources, and causing long-running operations that hold resources indefinitely. Unlike sudden flooding attacks, resource leak exploitation causes gradual degradation that may be harder to detect and diagnose.", "severity": "Medium"},
  {"id": "CAPEC-227", "name": "Sustained Client Engagement", "description": "The attacker maintains many concurrent connections to a server to exhaust connection pool limits and deny service to legitimate users. The Slowloris attack sends partial HTTP request headers at just enough speed to keep connections alive, never completing the request. Slow POST attacks send request bodies at an extremely slow rate. R-U-Dead-Yet (RUDY) sends HTTP POST requests with extremely long content-length headers followed by tiny data packets. These attacks require minimal bandwidth since each connection consumes negligible network resources but holds a server thread or connection slot indefinitely. A single attacker machine can exhaust a web server's connection pool with a few hundred concurrent slow connections, making this an asymmetric attack accessible to unsophisticated adversaries.", "severity": "Medium"},
  {"id": "CAPEC-469", "name": "HTTP DoS", "description": "The attacker sends specially crafted HTTP requests designed to exhaust web server resources through expensive processing operations. Techniques include sending requests with extremely large headers or cookies that consume parsing memory, HTTP request smuggling that causes backend servers to process ghost requests, requests targeting expensive server-side operations like complex regular expressions (ReDoS), API endpoints that trigger resource-intensive database queries, and requests exploiting compression libraries (decompression bombs). Application-specific attacks target features like PDF generation, image processing, video transcoding, or report generation that consume significant CPU and memory resources per request. These attacks are harder to mitigate than volumetric floods because the traffic appears legitimate.", "severity": "Medium"},
  {"id": "CAPEC-482", "name": "TCP Flood", "description": "The attacker floods the target with TCP packets to exhaust network bandwidth, server processing capacity, or connection state tracking resources. SYN floods send massive volumes of TCP SYN packets with spoofed source addresses, filling the server's half-open connection queue. ACK floods send unsolicited ACK packets to consume server resources processing invalid segments. RST floods disrupt existing legitimate connections. FIN floods exploit connection teardown processing. The attack overwhelms the server's ability to process legitimate traffic and may also exhaust state tracking tables on intermediate firewalls and load balancers. Modern mitigation includes SYN cookies, rate limiting, connection state tracking limits, and scrubbing services that filter malicious traffic upstream.", "severity": "Medium"},
  {"id": "CAPEC-528", "name": "XML Flood", "description": "The attacker sends large volumes of XML data or specially crafted XML documents to overwhelm XML parsers and exhaust server resources. Techniques include sending extremely large XML documents that consume memory during DOM parsing, XML entity expansion attacks (Billion Laughs/XML bomb) where nested entity definitions expand to exponential size, external entity references that cause the server to fetch large remote resources, and deeply nested XML structures that exhaust stack space during recursive parsing. A 1KB XML document using entity expansion can consume several gigabytes of memory when parsed. This attack is effective against SOAP-based web services, REST APIs accepting XML input, and any application that processes user-supplied XML without proper limits on document size and entity expansion.", "severity": "Medium"},
  {"id": "CAPEC-664", "name": "Server Side Request Forgery (SSRF)", "description": "The attacker induces the server-side application to make HTTP requests to arbitrary destinations, including internal network resources that are not directly accessible from the internet. By manipulating URL parameters, file import functions, webhook configurations, or any feature that accepts URLs, the attacker can scan internal networks, access cloud instance metadata endpoints (169.254.169.254) to steal IAM credentials and API tokens, interact with internal services like databases, caches (Redis, Memcached), and message queues, read local files via file:// protocol, and potentially achieve remote code execution on internal systems. Advanced SSRF exploitation chains include accessing cloud metadata services to obtain temporary credentials, then using those credentials to compromise the entire cloud environment. Blind SSRF variants use timing or out-of-band callbacks to confirm connectivity.", "severity": "High"},
  {"id": "CAPEC-221", "name": "Data Serialization External Entities Blowup", "description": "The attacker crafts XML documents containing entity definitions that reference each other in a nested pattern, causing exponential expansion when parsed (known as the Billion Laughs or XML Bomb attack). A typical payload defines a base entity, then defines progressively larger entities that each reference the previous one multiple times, resulting in a small input document (often under 1KB) that expands to consume gigabytes of memory during parsing. For example, 10 levels of entities each referencing the previous 10 times results in 10^10 (10 billion) copies of the base entity. This denial-of-service attack is effective against any XML parser that processes entity definitions, including SOAP services, XML-RPC endpoints, SAML processors, SVG parsers, and office document processors.", "severity": "High"},
  {"id": "CAPEC-201", "name": "Serialized Data External Linking", "description": "The attacker exploits XML External Entity (XXE) processing to force the server to access external or internal resources via entity declarations. By defining external entities using file:// URIs (to read local files like /etc/passwd, web.config, or AWS credentials), http:// URIs (to perform SSRF against internal services), or other protocol handlers (gopher://, ftp://, expect://), the attacker can exfiltrate sensitive data, map internal network infrastructure, and in some cases achieve remote code execution. Blind XXE variants use out-of-band data exfiltration through DNS lookups or HTTP callbacks to attacker-controlled servers. The attack targets any application processing user-supplied XML including document upload handlers, SOAP APIs, RSS/Atom feed parsers, and SAML implementations.", "severity": "High"},
  {"id": "CAPEC-586", "name": "Object Injection", "description": "The attacker injects malicious serialized objects into an application that deserializes untrusted data, triggering arbitrary code execution through manipulation of object properties and methods during the deserialization process. In Java, exploiting dangerous gadget chains in libraries like Apache Commons Collections, Spring Framework, or through ysoserial-generated payloads can achieve remote code execution. PHP object injection exploits magic methods (__wakeup, __destruct, __toString) that are automatically called during deserialization. Python pickle deserialization allows arbitrary code execution through the __reduce__ method. .NET BinaryFormatter and JavaScriptSerializer are similarly exploitable. The attack is particularly dangerous because a single untrusted deserialization endpoint can lead to complete system compromise.", "severity": "High"},
  {"id": "CAPEC-228", "name": "DTD Injection", "description": "The attacker injects malicious Document Type Definition (DTD) declarations into XML documents to manipulate how the XML parser processes the document. By introducing custom entity definitions, the attacker can reference external resources (external entities for XXE attacks), define internal entities for entity expansion attacks (XML bombs), override existing entity definitions to alter document semantics, and exploit parameter entities to exfiltrate data out-of-band. The injected DTD can be inline within the XML document or reference a remote DTD file hosted on an attacker-controlled server, enabling dynamic payload modification. Defense requires disabling DTD processing entirely using parser configuration options like disallow-doctype-decl or disabling external entity resolution.", "severity": "High"},
  {"id": "CAPEC-13", "name": "Subverting Environment Variable Values", "description": "The attacker manipulates environment variables to alter application behavior, bypass security controls, or inject malicious values into program execution. Critical targets include PATH (to make the application execute attacker-controlled binaries instead of legitimate ones), LD_PRELOAD/LD_LIBRARY_PATH (to inject malicious shared libraries on Linux), CLASSPATH (to load malicious Java classes), HTTP_PROXY/HTTPS_PROXY (to redirect application HTTP traffic through an attacker-controlled proxy), and application-specific variables that control database connections, API keys, or feature flags. In container environments, environment variables often contain secrets (database passwords, API tokens) that can be harvested. CI/CD pipelines using environment variables for configuration are particularly susceptible to pipeline manipulation attacks.", "severity": "Medium"},
  {"id": "CAPEC-39", "name": "Manipulating Opaque Client-based Data Tokens", "description": "The attacker modifies opaque tokens stored or transmitted on the client side—including cookies, hidden form fields, local storage values, JWT tokens, and URL parameters—to escalate privileges, impersonate other users, or bypass authorization controls. For JWT tokens, the attacker may exploit algorithm confusion (changing RS256 to HS256 and signing with the public key), none algorithm attacks, weak signing keys, or missing signature verification. Cookie manipulation includes modifying role flags (admin=true), user IDs, or encrypted values using bit-flipping attacks against CBC-mode encryption. Hidden field tampering can alter prices, quantities, or user references in e-commerce applications. Effective defense requires server-side validation of all token claims, strong cryptographic signing, and never trusting client-provided authorization data.", "severity": "High"},
  {"id": "CAPEC-21", "name": "Exploitation of Trusted Credentials", "description": "The attacker uses compromised legitimate credentials—obtained through phishing, credential dumping, breach databases, or insider access—to access protected resources while appearing as an authorized user. Because the authentication is technically valid, security controls designed to detect unauthorized access may not trigger alerts. The attacker can access email, file shares, cloud services, VPN, and internal applications using the victim's identity. This technique is foundational to many advanced attacks: initial access through compromised VPN credentials, lateral movement using dumped domain credentials, persistence through created accounts, and privilege escalation through exploited service accounts. Detection requires behavioral analytics that identify anomalous usage patterns even when authentication is successful.", "severity": "High"},
  {"id": "CAPEC-22", "name": "Exploiting Trust in Client", "description": "The attacker exploits the server's misplaced trust in client-side validation, client-side state management, or client-side security controls to bypass intended restrictions. Applications that rely on JavaScript validation without server-side verification, trust hidden form field values for pricing or authorization, depend on client-side feature flags for access control, or assume that thick clients enforce business rules correctly are vulnerable. The attacker uses browser developer tools, proxy tools like Burp Suite, or custom HTTP clients to modify requests after client-side processing, bypassing any validation or restrictions implemented in JavaScript. This fundamental flaw underlies many web application vulnerabilities and highlights the principle that all security enforcement must occur server-side.", "severity": "High"},
  {"id": "CAPEC-62", "name": "Cross Site Request Forgery", "description": "The attacker tricks an authenticated user's browser into making unintended requests to a web application where the user is currently logged in, exploiting the browser's automatic inclusion of cookies, HTTP authentication credentials, and client certificates with every request to a domain. The attacker hosts a malicious page, email, or advertisement containing auto-submitting forms, image tags with crafted src URLs, or JavaScript that triggers requests to the target application. Potential impacts include changing email addresses and passwords, transferring funds, modifying account settings, creating administrative accounts, and any state-changing operation the victim is authorized to perform. Modern defenses include anti-CSRF tokens (synchronizer token pattern), SameSite cookie attributes, custom request headers, and requiring re-authentication for sensitive operations.", "severity": "High"},
  {"id": "CAPEC-60", "name": "Reusing Session IDs (Session Replay)", "description": "The attacker captures or predicts valid session identifiers and uses them to impersonate the legitimate user's authenticated session. Session IDs may be obtained through network sniffing on unencrypted connections, cross-site scripting to steal cookies, accessing server logs that record session IDs in URLs, exploiting session ID predictability through weak random number generators, or intercepting session tokens from insecure storage. Once the attacker has a valid session ID, they can assume the victim's identity and access all functionality authorized for that session. Replay attacks work until the session expires or is invalidated, highlighting the importance of short session timeouts, secure cookie attributes (HttpOnly, Secure, SameSite), and session invalidation on logout.", "severity": "High"},
  {"id": "CAPEC-61", "name": "Session Fixation", "description": "The attacker sets a known session identifier in the victim's browser before the victim authenticates, then uses the same session ID to access the authenticated session after the victim logs in. The attack exploits applications that do not regenerate session IDs upon successful authentication. The attacker can set the session ID through URL parameters (if the application accepts session IDs in URLs), through injecting Set-Cookie headers via XSS or HTTP response splitting, through meta tags, or through an attacker-controlled subdomain setting parent domain cookies. After the victim authenticates with the pre-set session ID, the attacker's copy of that session ID now grants authenticated access. Prevention requires regenerating session IDs immediately after successful authentication and rejecting session IDs that haven't been server-issued.", "severity": "High"},
  {"id": "CAPEC-196", "name": "Session Credential Falsification through Forging", "description": "The attacker forges or manipulates session credentials to gain unauthorized access or escalate privileges within an application. This includes crafting valid-looking session cookies by reverse-engineering the session ID generation algorithm, decrypting weakly encrypted session tokens, exploiting JWT vulnerabilities (algorithm confusion, weak keys, missing validation), modifying serialized session objects stored in client-side cookies, and exploiting predictable session ID patterns. In applications that store session data in client-side cookies (rather than server-side session stores), the attacker may be able to tamper with serialized session data to modify user roles, permissions, or identity. Defense requires strong session ID generation using cryptographic random number generators, server-side session storage, and integrity protection through HMAC signatures.", "severity": "High"},
  {"id": "CAPEC-232", "name": "Exploitation of Privilege/Trust", "description": "The attacker exploits elevated privileges or misplaced trust relationships to perform unauthorized operations beyond their intended access level. This encompasses exploiting trust between federated identity providers, abusing delegated authentication tokens (OAuth tokens with excessive scopes), leveraging trusted certificates to sign malicious code, exploiting trust relationships between Active Directory domains and forests, abusing service accounts with excessive permissions, and exploiting trust in automated systems like CI/CD pipelines, orchestration tools, and inter-service authentication. In cloud environments, the attacker may exploit overly permissive IAM roles, resource policies that trust entire AWS accounts, or managed identity configurations that grant access to sensitive resources.", "severity": "High"},
  {"id": "CAPEC-122", "name": "Privilege Abuse", "description": "The attacker abuses legitimate privileges granted to their account or role to perform operations beyond the intended scope of their authorization. This includes administrators using their access for personal gain or sabotage, operators leveraging system access to exfiltrate data, developers using production credentials to access customer data, and service accounts with overly broad permissions being exploited after compromise. The attack is difficult to detect using traditional access controls because all operations are technically authorized under the abused account's permissions. Defense requires implementing least-privilege principles, separation of duties, privileged access management (PAM) solutions, monitoring for anomalous usage of privileged accounts, and just-in-time access provisioning.", "severity": "High"},
  {"id": "CAPEC-233", "name": "Privilege Escalation", "description": "The attacker obtains higher-level privileges than originally authorized by exploiting vulnerabilities in access control mechanisms, operating system components, or application logic. Vertical escalation elevates from regular user to administrator or root, while horizontal escalation accesses other users' resources at the same privilege level. Techniques include exploiting SUID/SGID binaries on Linux, abusing Windows service misconfigurations (unquoted service paths, weak service permissions), exploiting kernel vulnerabilities (dirty pipe, dirty cow), manipulating token privileges on Windows, abusing Active Directory misconfigurations (GPP passwords, Kerberoasting), cloud IAM policy exploitation, and container escape techniques. Tools like LinPEAS, WinPEAS, and BloodHound automate the discovery of privilege escalation paths.", "severity": "High"},
  {"id": "CAPEC-17", "name": "Using Malicious Files", "description": "The attacker delivers malicious files to compromise the target system, exploiting vulnerabilities in file parsers, document renderers, or user trust. File types include weaponized Office documents with macro payloads (VBA, XLM macros), PDF files exploiting reader vulnerabilities, LNK shortcut files with embedded commands, ISO/IMG disk images bypassing Mark-of-the-Web protections, HTML smuggling files that assemble malware from base64 data, polyglot files that are valid in multiple formats, and executable files disguised with document icons and double extensions. Delivery vectors include email attachments, shared file links, USB drives, and watering hole downloads. The attack chain typically progresses from initial execution through the malicious file to persistence, privilege escalation, and command-and-control establishment.", "severity": "High"},
  {"id": "CAPEC-145", "name": "Checksum Spoofing", "description": "The attacker modifies checksums, hashes, or integrity signatures to mask tampering of files, software packages, or network packets. Techniques include replacing legitimate file hashes on download pages after compromising the distribution server, generating collisions for weak hash algorithms (MD5, SHA-1) to create malicious files matching legitimate checksums, modifying package manager repositories to serve backdoored packages with valid-looking signatures, tampering with software update manifests, and manipulating TCP/IP checksums on intercepted packets. This attack undermines integrity verification mechanisms that users and systems depend on to validate software authenticity, making it a key component of supply chain attacks and software distribution compromise.", "severity": "Medium"},
  {"id": "CAPEC-148", "name": "Content Spoofing", "description": "The attacker injects false or misleading content into web pages, applications, or communications to deceive users into taking unintended actions. Techniques include text injection where user-controllable input is rendered as trusted page content, phishing pages embedded within legitimate application frames using iframes, email content manipulation to appear from trusted senders, manipulating Open Graph and social media preview metadata to misrepresent link destinations, and modifying cached content to serve false information. The spoofed content can direct users to enter credentials on fake login forms, download malicious software, transfer funds to attacker accounts, or disclose sensitive information. Content spoofing is often combined with social engineering to increase attack effectiveness.", "severity": "Medium"},
  {"id": "CAPEC-151", "name": "Identity Spoofing", "description": "The attacker assumes the identity of another entity (user, system, service, or organization) to gain unauthorized access to resources or trick victims into trusting malicious communications. Techniques include email address spoofing (forging From headers), IP address spoofing, DNS spoofing, caller ID spoofing for vishing, domain impersonation using typosquatting or homograph attacks (using similar-looking Unicode characters), certificate impersonation, and spoofing federated identity assertions (SAML assertions, OAuth tokens). In enterprise environments, the attacker may spoof Active Directory objects, Kerberos service principal names, or cloud identity provider responses. The attack exploits the fundamental trust that systems and users place in identity claims without sufficient verification.", "severity": "High"},
  {"id": "CAPEC-154", "name": "Resource Location Spoofing", "description": "The attacker manipulates references to resource locations (URLs, file paths, DNS records, API endpoints) to redirect users or applications to malicious content that appears to originate from a trusted source. Techniques include DNS hijacking to redirect domain resolution, typosquatting with look-alike domains, URL manipulation using open redirects, link manipulation in cached or proxied content, and manipulating application configurations that reference external resources. The spoofed resource appears to be at its expected location, bypassing user vigilance and automated URL filtering. This attack is effective against software update mechanisms, dependency management systems, content delivery networks, and any system that fetches resources based on configurable or user-influenced locations.", "severity": "Medium"},
  {"id": "CAPEC-173", "name": "Action Spoofing", "description": "The attacker tricks users into performing unintended actions by overlaying or repositioning user interface elements, commonly known as clickjacking. Techniques include overlaying transparent iframes containing target application pages over attacker-controlled content, using CSS opacity and positioning to hide malicious buttons beneath legitimate-looking elements, drag-and-drop hijacking (filejacking), touch event hijacking on mobile devices, and cursor manipulation that misaligns the visual cursor position with the actual click target. Sophisticated variants include likejacking (tricking users into liking/sharing social media content), strokejacking (capturing keystrokes in invisible fields), and multi-step clickjacking that walks victims through complex sequences of actions. Defense primarily relies on X-Frame-Options headers and Content-Security-Policy frame-ancestors directive.", "severity": "Medium"},
  {"id": "CAPEC-103", "name": "Clickjacking", "description": "The attacker loads a target web application within a transparent or disguised iframe on a malicious page and positions enticing UI elements to trick the victim into clicking on invisible elements of the target application. The victim believes they are interacting with the visible attacker-controlled page, but their clicks are actually registered on the hidden target application's buttons, links, or form elements. Attack scenarios include authorizing OAuth applications, changing security settings, deleting accounts, transferring funds, enabling camera/microphone access, and adding attacker-controlled administrators. Advanced techniques use multiple overlapping iframes and staged interactions to guide victims through multi-step operations. Prevention requires setting X-Frame-Options to DENY or SAMEORIGIN and using frame-ancestors CSP directives.", "severity": "Medium"},
  {"id": "CAPEC-164", "name": "Mobile Phishing", "description": "The attacker targets mobile device users through phishing attacks delivered via SMS (smishing), messaging apps (WhatsApp, Telegram, iMessage), push notifications, QR codes, mobile advertisements, and malicious mobile applications. Mobile phishing exploits the limited URL visibility in mobile browsers, users' habitual trust of text messages, and the difficulty of distinguishing legitimate from phishing sites on small screens. Sophisticated attacks use deeplinked URLs that open specific application views, progressive web apps (PWAs) that mimic native apps, and mobile-specific login pages that capture credentials for banking, corporate, and social media accounts. Mobile phishing campaigns often combine credential harvesting with malware delivery, installing surveillance software or banking trojans on the victim's device.", "severity": "Medium"},
  {"id": "CAPEC-98", "name": "Phishing", "description": "The attacker sends deceptive communications impersonating trusted entities to trick recipients into revealing credentials, installing malware, or taking actions that benefit the attacker. Modern phishing campaigns use sophisticated techniques including cloned legitimate websites with valid SSL certificates, bypassing email security through domain authentication (SPF/DKIM/DMARC) via compromised or closely matched domains, HTML smuggling attachments that bypass email scanning, browser-in-the-browser (BitB) attacks that simulate OAuth popups, and adversary-in-the-middle (AitM) phishing that proxies legitimate sites to capture both credentials and session tokens (bypassing MFA). Phishing kits like Evilginx2 and Modlishka automate AitM phishing infrastructure. The attack remains the most common initial access vector for both opportunistic and targeted attacks.", "severity": "High"},
  {"id": "CAPEC-163", "name": "Spear Phishing", "description": "The attacker sends highly targeted phishing messages crafted specifically for individual recipients or small groups, using personal information gathered through OSINT reconnaissance to make the message highly convincing. Information from LinkedIn profiles, social media, company websites, press releases, and previous data breaches is used to establish rapport and credibility. Spear phishing emails may reference recent projects, use internal company terminology, impersonate colleagues or executives (business email compromise), and include contextually relevant lures. Because these messages are individually crafted, they bypass generic spam filters and phishing detection systems. Spear phishing is the primary initial access technique for APT groups and is used in the vast majority of targeted attacks against enterprises, resulting in credential theft, malware delivery, or wire fraud.", "severity": "High"},
  {"id": "CAPEC-656", "name": "Voice Phishing (Vishing)", "description": "The attacker uses phone calls or voice messages to trick victims into revealing credentials, providing remote access, transferring funds, or taking other harmful actions. Techniques include impersonating IT support requesting MFA codes, posing as bank fraud departments to extract account details, pretending to be executive assistants requesting urgent wire transfers, and impersonating government agencies threatening legal action. Modern vishing uses AI-generated voice cloning (deepfakes) to convincingly impersonate known individuals, real-time voice modification software, spoofed caller ID showing legitimate numbers, and VoIP infrastructure for mass campaigns. Vishing is increasingly combined with smishing (SMS) and email phishing in multi-channel social engineering campaigns, and is a key technique in SIM-swapping attacks targeting cryptocurrency holders.", "severity": "Medium"},
  {"id": "CAPEC-543", "name": "Counterfeit Websites", "description": "The attacker creates convincing replicas of legitimate websites to harvest credentials, payment information, or personal data from unsuspecting visitors. Modern counterfeit sites use exact visual copies obtained through website cloning tools, valid HTTPS certificates from free providers like Let's Encrypt, domains that closely match the target through typosquatting (paypa1.com), homograph attacks using internationalized domain names (pаypal.com with Cyrillic 'a'), or compromised legitimate domains. Traffic is directed to counterfeit sites through phishing emails, search engine poisoning, malvertising, DNS hijacking, and social media promotion. Advanced counterfeit sites function as adversary-in-the-middle proxies, passing traffic to the real site while capturing credentials and session tokens in real time, effectively bypassing multi-factor authentication.", "severity": "High"},
  {"id": "CAPEC-89", "name": "Pharming", "description": "The attacker redirects legitimate domain name resolution to attacker-controlled servers, causing victims to reach malicious websites even when they type the correct URL or use bookmarks. Techniques include DNS cache poisoning (exploiting vulnerabilities in recursive DNS resolvers), compromising authoritative DNS servers, modifying local hosts files through malware, poisoning DHCP responses to set malicious DNS servers, attacking router DNS configurations, and BGP hijacking to redirect traffic at the network level. Unlike phishing, pharming does not require the victim to click a malicious link—the correct URL resolves to the wrong IP address. Large-scale pharming attacks have targeted DNS registrars and internet service providers to redirect millions of users simultaneously, making it a high-impact attack that undermines the fundamental trust in domain name resolution.", "severity": "High"},
  {"id": "CAPEC-185", "name": "Malicious Software Download", "description": "The attacker tricks users into downloading and executing malicious software disguised as legitimate applications, updates, utilities, or content. Distribution channels include compromised download sites, SEO poisoning to rank malicious downloads in search results, malvertising campaigns that redirect to fake software download pages, trojanized applications on unofficial app stores, social media campaigns promoting infected software, and typosquatted package manager repositories. The malicious software may be a trojanized version of the legitimate application (functioning normally while running a backdoor), a standalone dropper that installs additional malware, or ransomware disguised as a useful tool. Modern campaigns increasingly target developers through malicious npm packages, PyPI packages, and GitHub repositories that contain backdoored code.", "severity": "High"},
  {"id": "CAPEC-186", "name": "Malicious Software Update", "description": "The attacker compromises legitimate software update mechanisms to distribute malicious payloads to a wide base of users who trust the update process. This represents one of the most dangerous supply chain attack vectors because users and automated systems are conditioned to accept and install updates from trusted sources. Notable examples include the SolarWinds Sunburst attack (compromising the build process to inject a backdoor into 18,000+ enterprise deployments), the NotPetya attack (compromising Ukraine's M.E.Doc tax software updates), and the Codecov bash uploader compromise. Attack vectors include compromising build servers, poisoning CI/CD pipelines, stealing code signing certificates, compromising update server infrastructure, and MitM attacks against update channels lacking certificate pinning.", "severity": "High"},
  {"id": "CAPEC-438", "name": "Modification During Manufacture", "description": "The attacker modifies hardware or software during the manufacturing process to introduce backdoors, surveillance capabilities, or vulnerability points that persist throughout the product's lifecycle. Hardware modifications include adding rogue chips or components to circuit boards, modifying firmware in flash memory during factory programming, altering BIOS/UEFI images, and embedding radio transmitters for covert communication. Software modifications include inserting backdoor code into firmware, modifying bootloaders, and altering embedded operating systems. These supply chain attacks are extremely difficult to detect because the compromised products arrive with malicious modifications from the factory, pass quality assurance testing, and maintain valid manufacturer signatures. Nation-state actors are the primary perpetrators due to the operational access and sophistication required.", "severity": "High"},
  {"id": "CAPEC-439", "name": "Manipulation During Distribution", "description": "The attacker intercepts products during the distribution and shipping process to modify hardware or software before delivery to the end customer. Techniques include interdicting shipments at postal facilities or in transit, replacing legitimate firmware with modified versions, installing hardware implants, and repackaging tampered products to appear factory-sealed. This attack exploits the gap between manufacturer quality assurance and customer receipt where the product is outside either party's physical control. The modifications can include surveillance implants, backdoor malware, exfiltration mechanisms, or vulnerability introduction for later exploitation. Distribution-phase attacks are documented in intelligence agency toolkits and are a concern for organizations with high-security requirements purchasing networking equipment, servers, and storage devices.", "severity": "High"},
  {"id": "CAPEC-437", "name": "Supply Chain Attack", "description": "The attacker targets vulnerabilities in the supply chain to compromise the ultimate target indirectly, exploiting trust relationships between organizations and their suppliers, vendors, contractors, and open-source dependencies. Attack surfaces include compromising upstream software dependencies (npm, PyPI, Maven packages), poisoning pre-built container images, compromising CI/CD pipeline tools, attacking managed service providers (MSPs) to reach their clients, and compromising hardware component suppliers. Modern software supply chain attacks are particularly impactful because a single compromise can propagate to thousands of downstream victims (as demonstrated by SolarWinds, Kaseya VSA, and Log4Shell). The dependency tree of a modern application may include hundreds of transitive dependencies, each representing a potential supply chain attack vector.", "severity": "High"},
  {"id": "CAPEC-459", "name": "Creating a Rogue Certification Authority", "description": "The attacker creates a rogue Certificate Authority or compromises an existing CA to issue fraudulent TLS/SSL certificates that enable man-in-the-middle attacks against any domain without triggering browser warnings. With a trusted CA certificate installed in the victim's trust store, the attacker can intercept all HTTPS traffic, decrypt communications, inject content, and capture credentials. Techniques include compromising subordinate CA private keys, exploiting weaknesses in certificate issuance validation (as in the DigiNotar breach), creating rogue CA certificates through MD5 collision attacks, social engineering CA operators, and installing rogue root certificates through malware or insider access. Enterprise environments that deploy internal CAs are particularly targeted, as compromising the internal CA enables interception of all internal HTTPS communications.", "severity": "High"},
  {"id": "CAPEC-643", "name": "Identify Shared Hosting Infrastructure", "description": "The attacker identifies that the target organization uses shared hosting infrastructure (shared web servers, multi-tenant cloud environments, shared IP addresses, co-located data centers) to enable lateral attacks against co-hosted targets or to conduct cross-tenant attacks. Techniques include reverse DNS lookups, reverse IP lookups to find all domains on a shared IP, analyzing SSL/TLS certificates for shared hosting patterns, enumerating cloud resources in shared environments, and identifying CDN configurations that reveal hosting details. Once shared infrastructure is identified, the attacker can attempt cross-site scripting between co-hosted sites, exploit hypervisor vulnerabilities (VM escape), access shared file systems or databases through misconfigurations, or leverage one compromised tenant to attack others.", "severity": "Low"},
  {"id": "CAPEC-116", "name": "Excavation", "description": "The attacker systematically extracts data from a target system by exploiting insufficient access controls, information exposure vulnerabilities, or application logic flaws. Techniques include exploiting IDOR vulnerabilities to enumerate and download other users' data, scraping APIs that lack rate limiting or pagination controls, exploiting verbose error messages that reveal internal system details, accessing backup files and database dumps left in web-accessible directories, mining debug endpoints that expose application state, and extracting sensitive data through blind inference techniques. In cloud environments, misconfigured S3 buckets, Azure Blobs, and GCS buckets are common excavation targets. The attack can be automated to rapidly extract large volumes of data by iterating through predictable resource identifiers.", "severity": "Medium"},
  {"id": "CAPEC-117", "name": "Interception", "description": "The attacker intercepts communications between two parties to capture, record, or modify data in transit without the knowledge of the communicating parties. This encompasses network packet capture, wireless traffic interception, Bluetooth eavesdropping, electromagnetic emanation analysis (TEMPEST), optical surveillance of screens, phone tapping, and interception of cloud-to-cloud communications. In enterprise environments, interception of internal east-west traffic between microservices often reveals authentication tokens, API keys, and sensitive business data transmitted over unencrypted internal networks based on the assumption that internal traffic is trusted. Modern interception techniques include compromising network taps, exploiting SDN controller access, and leveraging cloud provider API access to mirror traffic.", "severity": "High"},
  {"id": "CAPEC-545", "name": "Pull Data from System Resources", "description": "The attacker leverages built-in system utilities and commands to extract sensitive data from configuration files, credential stores, environment variables, registries, and operating system data structures. On Windows, tools like reg query, cmdkey, vaultcmd, and PowerShell cmdlets (Get-Credential, Get-StoredCredential) extract stored credentials; netsh wlan show profiles reveals Wi-Fi passwords; dpapi can decrypt user data. On Linux, /etc/passwd, /etc/shadow, .bash_history, SSH configuration files, and process environment (/proc/PID/environ) contain valuable data. Cloud instances expose metadata services with IAM credentials and configuration data. This living-off-the-land technique avoids detection because it uses legitimate system tools rather than introducing external hacking software.", "severity": "Medium"},
  {"id": "CAPEC-546", "name": "Incomplete Data Deletion in Multi-Tenant Environment", "description": "The attacker recovers residual data left behind following incomplete data deletion in shared multi-tenant infrastructure. In cloud environments, storage volumes, database instances, and memory pages may retain data from previous tenants when resources are reallocated. Techniques include provisioning new storage volumes and scanning for residual data, analyzing memory pages in shared hypervisor environments, recovering data from incompletely wiped database partitions, and exploiting storage deduplication features that link to another tenant's data. This attack exploits the gap between logical deletion (marking data as deleted) and physical erasure (overwriting the storage media). It is particularly concerning in cloud environments where the physical infrastructure is entirely managed by the provider and tenants cannot verify that data scrubbing meets their security requirements.", "severity": "Medium"},
  {"id": "CAPEC-169", "name": "Footprinting", "description": "The attacker conducts systematic reconnaissance to gather information about the target organization, infrastructure, and personnel before launching attacks. Active techniques include network scanning, DNS zone transfers, traceroute mapping, and web application directory brute-forcing with tools like Nmap, dig, and Gobuster. Passive techniques include WHOIS lookups, DNS record enumeration, search engine dorking (Google hacking), Wayback Machine analysis, SSL certificate transparency log mining, social media profiling, job listing analysis (revealing technology stacks), public code repository analysis (GitHub, GitLab for exposed secrets), and leaked credential database searches. The intelligence gathered shapes the attacker's strategy, identifying attack surfaces, technology stacks, organizational structure, key personnel, and potential entry points for both technical and social engineering attacks.", "severity": "Low"},
  {"id": "CAPEC-224", "name": "Fingerprinting", "description": "The attacker identifies specific software versions, operating systems, and service configurations through analysis of response characteristics, error messages, header patterns, and protocol behaviors. Web server fingerprinting analyzes Server headers, default error pages, URL case sensitivity, and HTTP method support patterns. Application fingerprinting examines framework-specific headers (X-Powered-By, X-AspNet-Version), cookie naming conventions, HTML comment patterns, and JavaScript library signatures. OS fingerprinting through TCP/IP stack analysis examines TTL values, window sizes, DF flag usage, and TCP option ordering. Tools like Nmap, WhatWeb, Wappalyzer, and BuiltWith automate identification. The version information obtained enables targeted exploitation using known CVEs and published exploits specific to the identified software versions.", "severity": "Low"},
  {"id": "CAPEC-300", "name": "Port Scanning", "description": "The attacker probes target system ports to identify running services and their states (open, closed, filtered) as a foundation for vulnerability assessment and attack planning. Scan types include TCP Connect scans (completing the three-way handshake), SYN/stealth scans (detecting open ports without completing connections), FIN/XMAS/NULL scans (using TCP flag combinations to probe filtered ports), UDP scans (detecting UDP services like DNS, SNMP, and NFS), and version detection scans that probe service banners. Advanced techniques include fragmented packet scanning to evade firewalls, idle scanning using zombie hosts to mask the scanner's IP, and source port manipulation to bypass stateless firewall rules. Nmap is the de facto standard tool, with Masscan providing high-speed internet-scale scanning capabilities.", "severity": "Low"},
  {"id": "CAPEC-309", "name": "Network Topology Mapping", "description": "The attacker discovers the layout of the target network including subnets, routing paths, security boundaries, NAT configurations, VPN tunnels, and inter-site connections to plan lateral movement and identify critical infrastructure. Techniques include traceroute and TTL-based path discovery, SNMP community string exploitation to query routing tables, analysis of routing protocol broadcasts (OSPF, BGP), DNS zone transfer requests, ARP table analysis on compromised hosts, multicast group enumeration, and cloud VPC/subnet discovery through compromised cloud credentials. Understanding network topology reveals segmentation weaknesses, identifies high-value targets like domain controllers and jump boxes, maps trust boundaries, and enables planning of efficient lateral movement paths that minimize detection risk.", "severity": "Low"},
  {"id": "CAPEC-292", "name": "Host Discovery", "description": "The attacker discovers live hosts on a network to enumerate potential targets for further reconnaissance and exploitation. Techniques include ICMP ping sweeps (echo request/reply), ARP scans on local subnets (which cannot be blocked by host firewalls), TCP ping scans using SYN or ACK probes to common ports, UDP probes to known services, and DNS reverse lookups to discover hostnames. In cloud environments, host discovery may involve enumerating virtual machines through compromised cloud management APIs, querying container orchestration APIs (Kubernetes API server), and scanning elastic IP ranges. Stealthy approaches include slow scans spread over extended periods, randomized target ordering, and using allowlisted source addresses. Tools include Nmap, Masscan, arp-scan, and Netdiscover.", "severity": "Low"},
  {"id": "CAPEC-573", "name": "Process Footprinting", "description": "The attacker enumerates running processes on a compromised system to identify security software (antivirus, EDR, DLP agents), business applications, database services, backup agents, and other software that may be exploited or that must be evaded. On Windows, tools like tasklist, wmic process list, Get-Process PowerShell cmdlet, and Process Explorer reveal running processes. On Linux, ps aux, /proc filesystem enumeration, and top provide process information. The attacker uses this intelligence to identify which security products must be bypassed (determining specific EDR evasion techniques), discover running services that may contain credentials (password managers, SSH agents, database clients), and find applications vulnerable to exploitation for privilege escalation. This is typically one of the first post-exploitation activities.", "severity": "Low"},
  {"id": "CAPEC-580", "name": "System Footprinting", "description": "The attacker gathers detailed information about the target system including operating system version and patch level, hardware architecture, installed software and versions, user accounts, network configuration, and security settings. On Windows, commands like systeminfo, wmic os, whoami /all, net user, and ipconfig /all provide comprehensive system data. On Linux, uname -a, cat /etc/os-release, dpkg -l or rpm -qa, id, and ifconfig provide equivalent information. This reconnaissance enables the attacker to identify applicable kernel exploits, missing patches, misconfigured services, privilege escalation paths, and security control weak points specific to the target's exact configuration.", "severity": "Low"},
  {"id": "CAPEC-576", "name": "Group Permission Footprinting", "description": "The attacker enumerates group memberships and associated permissions to identify privilege escalation paths, especially in Active Directory environments. Tools like BloodHound/SharpHound map group nesting relationships, identify users with paths to Domain Admin, discover groups with write permissions on sensitive objects, and reveal attack paths through complex trust relationships. The attacker examines local group memberships (Administrators, Remote Desktop Users, Backup Operators), domain group relationships (nested groups that expand effective permissions), cloud IAM group memberships and attached policies, and application-specific role assignments. Identifying a regular user account that has a group membership chain leading to privileged access often reveals an escalation path that is not apparent through simple enumeration.", "severity": "Low"},
  {"id": "CAPEC-497", "name": "File Discovery", "description": "The attacker searches the file system for sensitive files including credential files (.kdbx password databases, .ppk SSH keys, .pfx certificates, browser credential stores), configuration files with embedded passwords (web.config, .env, application.properties, docker-compose.yml), financial documents, intellectual property, personally identifiable information, and operational security data. Search techniques include recursive file enumeration with extensions and name pattern matching, content-based searches using grep or findstr for strings like 'password', 'secret', and 'api_key', and automated tools like Seatbelt, LaZagne, and Snaffler that target known sensitive file patterns. In cloud environments, improperly secured storage buckets, shared drives, and code repositories are primary targets for credential and data discovery.", "severity": "Low"},
  {"id": "CAPEC-150", "name": "Collect Data from Common Resource Locations", "description": "The attacker searches well-known and commonly used file paths for configuration files, credentials, secrets, and sensitive data. Common targets include web server roots (robots.txt, .htaccess, .git directories), application configuration paths (/etc/nginx, /etc/apache2, /var/www), user home directories (.ssh/id_rsa, .bash_history, .aws/credentials, .azure/), temp directories, recycle bin/trash, database backup locations, log file directories (/var/log, Windows Event Logs), and cloud instance metadata endpoints (http://169.254.169.254). CI/CD systems commonly store secrets in .env files, Jenkinsfile, .github/workflows, and docker-compose.yml. Cloud configuration directories (.aws, .azure, .gcp, .kube) in user home directories often contain long-lived access credentials.", "severity": "Medium"},
  {"id": "CAPEC-113", "name": "Interface Manipulation", "description": "The attacker manipulates application programming interfaces (APIs), web service interfaces, or inter-process communication channels to bypass security controls, access unauthorized functionality, or extract data. Techniques include modifying API request parameters to access other users' data (IDOR), removing or modifying authorization headers, sending requests directly to backend APIs bypassing the frontend, exploiting GraphQL introspection to discover undocumented operations, manipulating REST API pagination to extract bulk data, abusing SOAP action header manipulation, and exploiting webhook endpoints with forged payloads. API testing tools like Burp Suite, Postman, and specialized tools like Arjun (for parameter discovery) and GraphQLmap enable systematic API interface attack surface enumeration and exploitation.", "severity": "High"},
  {"id": "CAPEC-115", "name": "Authentication Bypass", "description": "The attacker circumvents authentication mechanisms to gain unauthorized access without providing valid credentials. Techniques include exploiting authentication logic flaws (default credentials, SQL injection in login queries, authentication state confusion), manipulating client-side authentication checks (removing JavaScript validation), exploiting race conditions in authentication flows, bypassing multi-factor authentication (SIM swapping, MFA fatigue, AitM phishing), abusing password reset flows, exploiting SSO/SAML vulnerabilities (XML signature wrapping, assertion replay), and leveraging insecure direct object references to access authenticated-only resources. In API contexts, missing authentication on new endpoints, insecure API key validation, and JWT algorithm confusion attacks are common bypass vectors.", "severity": "High"},
  {"id": "CAPEC-114", "name": "Authentication Abuse", "description": "The attacker exploits weaknesses in authentication implementation details to gain unauthorized access or elevate privileges without completely bypassing authentication. This includes session fixation (pre-setting session IDs before victim authenticates), concurrent session exploitation (using sessions not properly invalidated on password change), remember-me token prediction or theft, OAuth authorization code interception, SAML response replay, Kerberos ticket manipulation, and exploiting inconsistent authentication states across microservices (where one service validates authentication differently than others). The attacker may have some level of legitimate access but exploits authentication weaknesses to gain access beyond their intended authorization level or to impersonate other users.", "severity": "High"},
  {"id": "CAPEC-87", "name": "Forceful Browsing", "description": "The attacker directly accesses restricted pages, admin panels, configuration files, or API endpoints by guessing or brute-forcing URLs that are not linked from the public-facing portions of the application but exist on the server. Tools like Gobuster, DirBuster, Feroxbuster, and ffuf use extensive wordlists to discover hidden directories (/admin, /backup, /debug, /test), backup files (.bak, .old, .swp), configuration files (web.config, .env, .htpasswd), version control directories (.git, .svn), and undocumented API endpoints. Many applications rely on obscurity rather than access controls for sensitive functionality, assuming that if a page isn't linked, it won't be found. This technique also reveals development artifacts, staging environments, and deprecated functionality that may contain vulnerabilities addressed in current versions.", "severity": "Medium"},
  {"id": "CAPEC-127", "name": "Directory Indexing", "description": "The attacker exploits enabled directory listing on web servers to enumerate all files within a directory, discovering application structure, source code files, configuration files, database backups, log files, and other sensitive content that was not intended to be publicly accessible. When a directory has no index page (index.html, index.php) and directory listing is enabled in the web server configuration, the server returns a full listing of all files. The attacker systematically browses these listings to identify files containing credentials, database connection strings, API keys, and other secrets. Common findings include .sql database dumps, .bak backup files, .log files with sensitive data, .git repositories with full source code history, and configuration files with embedded credentials.", "severity": "Low"},
  {"id": "CAPEC-34", "name": "HTTP Response Splitting", "description": "The attacker injects CRLF (Carriage Return Line Feed: \\r\\n) sequences into HTTP response headers through user-controllable input, enabling them to inject arbitrary headers, split a single HTTP response into multiple responses, and control the body of injected responses. By injecting \\r\\n\\r\\n sequences, the attacker terminates the header section and begins an arbitrary response body that can contain malicious HTML, JavaScript, or redirect instructions. This enables cache poisoning (storing malicious content in web caches), cross-site scripting (injecting scripts into response bodies), session fixation (injecting Set-Cookie headers), and phishing (injecting redirects). Modern web frameworks largely prevent this by encoding CRLF in header values, but legacy applications and custom header manipulation code remain vulnerable.", "severity": "Medium"},
  {"id": "CAPEC-33", "name": "HTTP Request Smuggling", "description": "The attacker exploits discrepancies in how front-end servers (reverse proxies, load balancers, CDNs, WAFs) and back-end servers parse HTTP request boundaries, particularly disagreements about request length determination via Content-Length versus Transfer-Encoding headers. By crafting ambiguous requests, the attacker smuggles a hidden request within the boundaries of a visible request. This enables bypassing security controls (WAFs see one request while the backend processes two), cache poisoning, request hijacking (prepending malicious data to another user's request), credential theft, and unauthorized access to restricted endpoints. Variations include CL.TE (front-end uses Content-Length, backend uses Transfer-Encoding), TE.CL (reverse), and TE.TE (exploiting different Transfer-Encoding parsing). Detection requires testing with tools like smuggler.py or Burp Suite's HTTP Request Smuggler extension.", "severity": "High"},
  {"id": "CAPEC-549", "name": "Local Execution of Code", "description": "The attacker executes malicious code directly on the target system after gaining initial access, either through exploitation, social engineering, or physical access. Execution techniques include running compiled executables, executing scripts through installed interpreters (PowerShell, Python, bash, VBScript), leveraging native OS tools for fileless execution (MSHTA, WMIC, CertUtil, BITSAdmin), abusing runtime environments like .NET's Assembly.Load for in-memory execution, and using Living-off-the-Land binaries (LOLBins) that are pre-installed on target systems. Fileless malware techniques that execute entirely in memory without writing to disk are increasingly common to evade endpoint detection. Post-exploitation frameworks like Cobalt Strike, Metasploit, and Sliver provide comprehensive local execution capabilities.", "severity": "High"},
  {"id": "CAPEC-552", "name": "Install Rootkit", "description": "The attacker installs a rootkit to maintain persistent, stealthy access to a compromised system by modifying the operating system, hypervisor, firmware, or bootloader to conceal the attacker's presence. User-mode rootkits hook APIs and modify libraries to hide processes, files, network connections, and registry keys from system tools. Kernel-mode rootkits install drivers or modify kernel structures for deeper concealment, hiding from even advanced endpoint detection tools. Bootkit variants infect the Master Boot Record (MBR) or UEFI firmware to load before the operating system, surviving OS reinstallation. Hypervisor-level rootkits virtualize the host OS and run beneath it. Detection of advanced rootkits requires offline analysis, firmware integrity verification, and hardware-assisted security features like Secure Boot and Intel STM.", "severity": "High"},
  {"id": "CAPEC-578", "name": "Disable Security Software", "description": "The attacker disables, tampers with, or evades endpoint security software to prevent detection of subsequent attack activities. Techniques include killing AV/EDR processes through privileged access, stopping security services (Windows Defender, CrowdStrike Falcon), patching ETW (Event Tracing for Windows) providers to blind security tools, unhooking NTDLL.dll to remove EDR userland hooks, loading vulnerable drivers to disable kernel-level protections (BYOVD - Bring Your Own Vulnerable Driver), modifying security product configurations through registry changes or GPO manipulation, exploiting tamper protection weaknesses, and using exclusion paths to stage malware in directories exempted from scanning. This is typically an early post-exploitation action to create a safe operating environment.", "severity": "High"},
  {"id": "CAPEC-579", "name": "Replace Binaries", "description": "The attacker replaces legitimate system binaries, service executables, or application files with malicious versions to achieve persistent code execution, escalate privileges, or establish backdoor access. On Windows, targets include accessibility features (sethc.exe, utilman.exe, narrator.exe) that can be triggered from the login screen, system services that restart automatically, and scheduled task executables. On Linux, targets include login shells, cron job scripts, systemd service binaries, and commonly-used utilities. The replacement binary may include the original functionality (trojanized binary) to avoid detection, or may be a completely different executable. DLL side-loading is a variant where a malicious DLL is placed alongside a legitimate application that loads it through the DLL search order. Detection requires file integrity monitoring and comparison against known-good baselines.", "severity": "High"},
  {"id": "CAPEC-541", "name": "Application Fingerprinting", "description": "The attacker determines the specific web application framework, CMS, and server-side technology stack through analysis of response characteristics, URL patterns, file extensions, error messages, and application-specific artifacts. Techniques include analyzing HTTP response headers (Server, X-Powered-By, X-AspNet-Version), default files and directories (/wp-admin, /administrator, /elmah.axd), cookie naming conventions (JSESSIONID for Java, PHPSESSID for PHP, ASP.NET_SessionId for .NET), HTML meta tags and generator metadata, JavaScript library fingerprints, CSS framework patterns, and favicon hashes. Automated tools like Wappalyzer, WhatWeb, and BuiltWith can rapidly identify technology stacks. This intelligence enables the attacker to search for known vulnerabilities specific to the identified versions and plan targeted exploitation.", "severity": "Low"},
  {"id": "CAPEC-129", "name": "Pointer Manipulation", "description": "The attacker corrupts pointer values in memory through buffer overflows, use-after-free conditions, or type confusion vulnerabilities to redirect program flow, access arbitrary memory locations, or achieve code execution. Techniques include overwriting function pointers (vtable entries in C++ objects, callback pointers in structures), corrupting heap metadata pointers (freelists in dlmalloc/ptmalloc), manipulating pointers to achieve arbitrary read/write primitives, and exploiting dangling pointers that reference freed memory that has been reallocated with attacker-controlled content. In modern exploit development, pointer manipulation is a fundamental building block combined with information leaks to defeat ASLR and with techniques like ROP/JOP to defeat DEP. This vulnerability class enables the most severe exploitation outcomes.", "severity": "High"},
  {"id": "CAPEC-176", "name": "Configuration/Environment Manipulation", "description": "The attacker modifies system configuration files, environment variables, registry entries, or runtime settings to weaken security controls, enable attack capabilities, or establish persistence. Examples include modifying firewall rules to allow inbound connections, changing proxy settings to route traffic through attacker-controlled systems, disabling SELinux or AppArmor enforcement, modifying sudo configuration to grant password-less access, adding entries to crontab or Windows Task Scheduler, modifying shared library search paths (LD_PRELOAD, PATH manipulation), changing DNS resolver configuration to attacker-controlled servers, and weakening TLS settings to enable interception. In containerized environments, modifying container runtime configurations, Kubernetes manifests, or Docker daemon settings can cascade to all workloads.", "severity": "Medium"},
  {"id": "CAPEC-180", "name": "Exploiting Incorrectly Configured Access Control Security Levels", "description": "The attacker exploits misconfigured access controls to access resources, functionality, or data that should be restricted. Common misconfigurations include overly permissive file system permissions (world-readable sensitive files), misconfigured cloud storage ACLs (public S3 buckets, open Azure Blobs), broken RBAC configurations missing deny rules, API endpoints lacking authentication requirements, database servers accepting remote connections without authentication, administrative interfaces accessible from untrusted networks, and overly permissive CORS policies allowing cross-origin access. In cloud environments, overly broad IAM policies (using wildcard * resource permissions), publicly accessible security groups, and misconfigured resource policies are prevalent. Automated scanning tools continuously probe for these misconfigurations across the internet.", "severity": "High"},
  {"id": "CAPEC-212", "name": "Functionality Misuse", "description": "The attacker uses legitimate application functionality in unintended ways to achieve malicious objectives without exploiting any technical vulnerability. Examples include abusing password reset flows for account enumeration, using file export features to exfiltrate data in bulk, leveraging email/notification features as spam relays, abusing referral systems for profit, exploiting free-tier cloud services for cryptocurrency mining, misusing file sharing features for malware distribution, leveraging search functionality to discover sensitive content, and abusing API pagination to extract entire datasets. This attack category is particularly challenging to defend against because the attacker is using features as designed—the security failure is in not anticipating or limiting the misuse potential of legitimate functionality.", "severity": "Medium"},
  {"id": "CAPEC-216", "name": "Communication Channel Manipulation", "description": "The attacker manipulates the communication channel between two endpoints to intercept, modify, drop, replay, or inject messages. Beyond traditional man-in-the-middle attacks, this includes manipulating DNS to redirect communications, ARP spoofing to control local network traffic flow, BGP hijacking to reroute internet traffic through attacker-controlled networks, exploiting weaknesses in wireless protocols (WEP/WPA2 cracking, KRACK attacks, BlueBorne), compromising SDN controllers to manipulate network flows, and manipulating application-level communication channels like WebSocket connections, gRPC streams, and message queue systems. The attacker may selectively modify specific messages while passing others unchanged, making detection through traffic anomaly analysis more difficult than full interception.", "severity": "High"},
  {"id": "CAPEC-223", "name": "Exploitation of Mis-configured or Weak Authentication", "description": "The attacker exploits weak authentication schemes, misconfigured authentication mechanisms, or incomplete authentication implementations to gain unauthorized access. Specific weaknesses include HTTP Basic Authentication over unencrypted channels (base64-encoded credentials easily decoded from captured traffic), missing authentication on internal API endpoints that are inadvertently exposed, weak API key validation (keys embedded in client-side code, transmitted in URLs, not rotated), OAuth misconfiguration (missing state parameter enabling CSRF, over-scoped tokens, token leakage through redirect URI manipulation), SAML implementation flaws, and partial authentication bypass (completing only one factor of MFA). The attacker may also exploit trust inheritance where authentication to one service incorrectly grants access to other services.", "severity": "High"},
  {"id": "CAPEC-215", "name": "Fuzzing for Application Mapping", "description": "The attacker submits random, malformed, or boundary-case data to application inputs to discover hidden parameters, undocumented endpoints, error handling paths, and application behavior under unexpected conditions. Fuzzing tools like ffuf, wfuzz, and Burp Suite Intruder systematically inject payloads into URL paths, query parameters, headers, cookie values, form fields, and request bodies. The attacker analyzes response variations (status codes, response sizes, response times, error messages) to identify valid parameters, hidden directories, authentication bypasses, and input handling vulnerabilities. Content discovery fuzzing uses wordlists of common file and directory names, while parameter fuzzing discovers hidden query parameters that modify application behavior or expose debug functionality.", "severity": "Low"},
  {"id": "CAPEC-214", "name": "Fuzzing for Protocol Payload", "description": "The attacker submits random, malformed, or protocol-violating data to network protocol implementations to discover parsing vulnerabilities, buffer overflows, crash conditions, and unexpected behaviors. Protocol fuzzers like boofuzz, AFL, and LibFuzzer generate test cases by mutating valid protocol messages, generating random data conforming to protocol grammars, or using evolutionary algorithms to maximize code coverage. Targets include TCP/IP stack implementations, TLS libraries, HTTP parsers, DNS resolvers, SMTP servers, IoT protocols (MQTT, CoAP), and industrial control system protocols (Modbus, DNP3). Discovered crashes indicate memory corruption vulnerabilities that often lead to remote code execution. Fuzzing campaigns against widely-used libraries like OpenSSL, curl, and Linux kernel have yielded critical vulnerabilities.", "severity": "Low"},
  {"id": "CAPEC-267", "name": "Leverage Alternate Encoding", "description": "The attacker uses alternate character encodings, representation formats, or encoding schemes to bypass input validation, output encoding, and web application firewalls that only check for specific encoding patterns. Techniques include URL encoding (%3Cscript%3E), double URL encoding (%253Cscript%253E), Unicode/UTF-8 encoding (using full-width characters or overlong encodings), HTML entity encoding (&#60;script&#62;), Base64 encoding, hex encoding, octal encoding, and mixed encoding combining multiple schemes. Different layers of the application stack (WAF, web server, application framework, database) may decode input at different stages, creating opportunities for encoding that bypasses one layer but is decoded by another. This technique is primarily used to bypass XSS filters, SQL injection detection, command injection prevention, and path traversal protections.", "severity": "Medium"},
  {"id": "CAPEC-468", "name": "Generic Cross-Browser Cross-Domain Theft", "description": "The attacker exploits browser weaknesses, same-origin policy bypasses, or cross-domain communication misconfigurations to steal data across domain boundaries. Attack vectors include exploiting misconfigured CORS policies (Access-Control-Allow-Origin: * with credentials), abusing postMessage handlers that don't validate message origins, exploiting WebSocket cross-origin connections, leveraging Flash/Silverlight crossdomain.xml misconfigurations, DNS rebinding attacks that bypass same-origin policy, and exploiting timing side channels to infer cross-origin data. Browser-specific bugs and implementation differences in same-origin policy enforcement periodically create new cross-domain attack vectors. The stolen data may include authentication tokens, personal information, financial data, and any other content accessible from the victim's browser context.", "severity": "High"},
  {"id": "CAPEC-540", "name": "Overread Buffers", "description": "The attacker exploits out-of-bounds read vulnerabilities to read beyond the intended buffer boundary and extract sensitive data from adjacent memory regions. Unlike buffer overflows that write beyond boundaries, overread vulnerabilities leak data without modifying memory, making them harder to detect through crash monitoring. The most famous example is the Heartbleed vulnerability (CVE-2014-0160) in OpenSSL, where a crafted TLS heartbeat request could read up to 64KB of server memory per request, potentially leaking private keys, session cookies, passwords, and other sensitive data processed by the server. Repeated exploitation can extract different memory contents each time. Similar vulnerabilities in image parsers, document processors, and network protocol implementations can leak heap contents, stack data, or kernel memory.", "severity": "High"},
  {"id": "CAPEC-609", "name": "Cellular Traffic Intercept", "description": "The attacker intercepts cellular communications using rogue base stations (IMSI catchers/Stingrays), exploiting weaknesses in cellular protocols (SS7 vulnerabilities in 2G/3G networks, GTP protocol exploitation, Diameter protocol attacks in 4G/5G), and SIM-based attacks (SIM swapping through social engineering of carriers, SIM jacking through remote SIM toolkit vulnerabilities). IMSI catchers force mobile devices to connect through the rogue station by broadcasting a stronger signal than legitimate towers, enabling interception of calls, SMS messages, and mobile data. SS7 protocol vulnerabilities allow remote tracking of phone locations, interception of SMS messages (including MFA codes), and call redirection from anywhere in the world. These attacks target mobile authentication channels, enabling MFA bypass through SMS interception.", "severity": "High"},
  {"id": "CAPEC-610", "name": "Cellular Data Injection", "description": "The attacker injects malicious data into cellular communications channels to compromise mobile devices, intercept sessions, or redirect traffic. Techniques include injecting malicious content through rogue base stations (serving fake captive portals, injecting JavaScript into HTTP traffic, pushing malicious carrier configuration profiles), exploiting RCS (Rich Communication Services) vulnerabilities, abusing carrier-level MMS processing to deliver exploits, and injecting malicious USSD codes. Advanced attacks exploit baseband processor vulnerabilities through crafted cellular protocol messages, potentially achieving code execution on the mobile device's radio modem with escalation to the application processor. These attacks are particularly dangerous because they exploit the trusted relationship between mobile devices and the cellular network infrastructure.", "severity": "High"},
  {"id": "CAPEC-650", "name": "Upload a Web Shell to a Web Server", "description": "The attacker uploads a web shell (a server-side script providing remote command execution through a web interface) to a web server by exploiting file upload vulnerabilities, CMS plugin flaws, or other entry points. Popular web shells include China Chopper, c99, WSO, p0wny-shell for PHP; ASPXSpy for ASP.NET; and JspSpy for Java. The attacker bypasses upload restrictions through file extension manipulation (shell.php5, shell.pHp, shell.php.jpg), Content-Type header manipulation, null byte injection, and archive extraction path traversal. Once deployed, web shells provide persistent backdoor access for command execution, file management, database interaction, and lateral movement. Advanced web shells use encryption, fileless memory-resident techniques, and legitimate-looking file names to evade detection by file integrity monitoring and antivirus solutions.", "severity": "High"},
  {"id": "CAPEC-644", "name": "Use of Captured Hashes (Pass The Hash)", "description": "The attacker uses captured NTLM password hashes to authenticate to Windows services without knowing or cracking the plaintext password. After obtaining hashes through LSASS memory dumping (Mimikatz), SAM database extraction, NTDS.dit extraction, or network capture (LLMNR/NBT-NS poisoning using Responder), the attacker uses tools like Mimikatz (sekurlsa::pth), Impacket (psexec.py, wmiexec.py, smbexec.py), CrackMapExec, or Evil-WinRM to authenticate using the hash directly. This enables lateral movement across Windows environments where the compromised account has local administrator access on multiple machines. Pass-the-hash is a fundamental Active Directory attack technique that exploits the NTLM authentication protocol's design of using hashes rather than passwords for authentication. Defense requires Credential Guard, LAPS, restricting admin account usage, and monitoring for anomalous authentication patterns.", "severity": "High"},
  {"id": "CAPEC-645", "name": "Use of Captured Tickets (Pass The Ticket)", "description": "The attacker uses stolen Kerberos tickets (TGT or service tickets) to authenticate as another user or access services without knowing the user's password. Tickets are obtained through memory extraction from compromised systems (Mimikatz, Rubeus), Golden Ticket attacks using the KRBTGT hash (granting domain-wide access for up to 10 years), Silver Ticket attacks using service account hashes (accessing specific services), and Diamond Ticket attacks that request legitimate tickets and modify PAC data. The attacker imports the captured tickets into their session using tools like Mimikatz (kerberos::ptt), Rubeus (ptt), or Impacket to authenticate transparently across the domain. This technique enables stealthy lateral movement because Kerberos authentication events appear legitimate in security logs. Defense requires regular KRBTGT password rotation, privileged access workstations, and Kerberos event monitoring.", "severity": "High"},
  {"id": "CAPEC-653", "name": "Use of Known Operating System Credentials", "description": "The attacker uses default or widely known credentials that are built into operating systems, services, and applications to access systems where administrators have not changed the defaults. Default credentials are documented in vendor manuals, posted on security databases (default-password.info, CIRT.net), and compiled in tool databases. Targets include network devices (Cisco admin/admin, router manufacturer defaults), database systems (SQL Server sa with blank password, MySQL root with no password, MongoDB with no auth), IoT devices (admin/admin universally common), virtual appliances (VMware, Citrix defaults), cloud platform AMIs deployed with default SSH keys, and development tools (Jenkins, Grafana default admin accounts). Automated scanners systematically test known defaults across large IP ranges, making internet-facing systems with default credentials typically compromised within hours of deployment.", "severity": "High"},
  {"id": "CAPEC-554", "name": "Functionality Bypass", "description": "The attacker circumvents application security functionality—such as authentication gates, authorization checks, input validation, rate limiting, payment verification, or approval workflows—to perform unauthorized actions. Techniques include accessing API endpoints directly to skip client-side validation, manipulating workflow state parameters to skip required steps, exploiting race conditions to bypass balance checks, modifying client-side feature flags that control access to premium functionality, tampering with request parameters that determine which security checks are applied, and exploiting logical flaws in multi-step processes. For example, skipping from step 1 to step 3 in a payment workflow, or modifying a boolean parameter from 'requires_approval=true' to 'requires_approval=false'. This attack targets business logic rather than technical vulnerabilities and requires understanding of the application's workflow design.", "severity": "High"},
  {"id": "CAPEC-594", "name": "Traffic Injection", "description": "The attacker injects traffic into a network communication channel to inject malicious content, modify legitimate data, disrupt services, or exploit protocol implementations. Techniques include ARP injection on local networks, DNS response injection to redirect traffic, TCP session injection using predicted sequence numbers, HTTP content injection through compromised network devices or ISP-level equipment, BGP route injection to redirect internet traffic, and injection into wireless protocols (deauthentication attacks, beacon frame injection). Modern TLS provides protection against content injection on encrypted channels, but network-level injection attacks (ARP, DNS, BGP) affect the routing layer below TLS and can redirect connections entirely. In industrial control systems, protocol injection attacks against Modbus, DNP3, or EtherNet/IP can directly manipulate physical processes.", "severity": "High"},
  {"id": "CAPEC-632", "name": "Exploiting Incorrectly Configured SSL/TLS", "description": "The attacker exploits SSL/TLS misconfigurations to intercept, decrypt, or manipulate encrypted communications. Misconfigurations include supporting deprecated protocol versions (SSLv3, TLS 1.0, TLS 1.1) vulnerable to POODLE and BEAST attacks, using weak cipher suites (RC4, DES, export-grade ciphers), missing certificate validation in client applications, self-signed certificates in production, expired certificates, certificate chain issues, missing HSTS headers enabling SSL stripping, and certificate private key exposure. The attacker may perform protocol downgrade attacks (forcing the use of weaker protocols through TLS_FALLBACK_SCSV absence), exploit specific cipher suite vulnerabilities (CRIME, BREACH for compression-based attacks, Lucky13 for CBC timing attacks), or leverage certificate-related issues for MitM interception. Tools like testssl.sh, sslyze, and SSL Labs scanner identify these misconfigurations.", "severity": "High"},
  {"id": "CAPEC-633", "name": "Token Impersonation", "description": "The attacker steals, forges, or manipulates authentication tokens to impersonate legitimate users or services. Token types include OAuth 2.0 access tokens and refresh tokens, JSON Web Tokens (JWTs), SAML assertions, Kerberos tickets, API keys, session tokens, and cloud provider temporary credentials (AWS STS tokens, Azure managed identity tokens). Attack techniques include token theft through XSS or request interception, JWT algorithm confusion (changing RS256 to HS256), JWK injection, kid claim manipulation, token replay after session invalidation, OAuth token theft through redirect URI manipulation, SAML response forgery through XML signature wrapping, and cloud metadata service token theft. Successful token impersonation provides the same access as the legitimate token holder without requiring their credentials.", "severity": "High"},
  {"id": "CAPEC-634", "name": "Probe Audio and Video Peripherals", "description": "The attacker accesses audio and video hardware (webcams, microphones, screen recording) on a compromised system for surveillance, intelligence gathering, or blackmail purposes. After gaining code execution through malware or exploitation, the attacker enumerates available media devices using platform APIs (DirectShow on Windows, AVFoundation on macOS, V4L2 on Linux) and activates recording capabilities. Advanced techniques disable hardware LED indicators that normally signal camera activity, capture from multiple devices simultaneously, and exfiltrate recordings through covert channels. Mobile device compromise additionally enables GPS tracking, call recording, and ambient audio capture. Some RATs (Remote Access Trojans) like DarkComet, njRAT, and Quasar specifically feature webcam and microphone surveillance capabilities as core functions.", "severity": "Medium"},
  {"id": "CAPEC-270", "name": "DNS Rebinding", "description": "The attacker manipulates DNS resolution timing to bypass same-origin policy restrictions and access internal network resources through a victim's browser. The attack works by first resolving the attacker's domain to a legitimate external IP that serves malicious JavaScript, then quickly changing the DNS record to point to an internal IP address (like 192.168.1.1 or 127.0.0.1). The browser's same-origin policy still considers requests to be same-origin (same domain), so the JavaScript can now read responses from the internal service. This enables port scanning of internal networks, accessing internal web applications (routers, printers, NAS devices, internal APIs), exploiting unauthenticated or weakly-authenticated internal services, and exfiltrating data from network-segregated environments. Effective defense requires DNS pinning, validating Host headers on internal services, and preventing external JavaScript from making requests to RFC1918 addresses.", "severity": "High"}
]

out = pathlib.Path(r"c:\AlexDev\AttackTreeBuilder\backend\app\reference_data\capec.json")
out.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
